<template>
  <div v-loading="loading">
    <OrderInfo :info="orderInfoList" />
    <LedgerInfo :data="lendgerInfoData" />
    <RefundInfo
      :data="refundInfoData"
      :arr="concatArr"
    />
  </div>
</template>
<script>
import { GetOrderInfoList } from '@/api/datacube'
import OrderInfo from './companydata/orderinfo.vue' // 訂單信息
import LedgerInfo from './companydata/ledgerinfo.vue' // 分賬信息
import RefundInfo from './companydata/refundinfo.vue' // 退款信息
export default {
  components: {
    OrderInfo,
    RefundInfo,
    LedgerInfo
  },
  data () {
    return {
      concatArr: [],
      testPosition: 0,
      orderInfoList: {}, // 訂單信息
      lendgerInfoData: [], // 分賬信息表格
      refundInfoData: [], // 退款信息表格
      loading: true,
      isShowLedger: false, // 是否展示分賬信息
      isShowRefund: false // 是否展示退款信息
    }
  },
  mounted () {
    this.onGetDetail()
  },
  methods: {
    rowspan (spanArr, position, spanName) {
      this.refundInfoData.forEach((item, index) => {
        if (index === 0) {
          spanArr.push(1)
          position = 0
        } else {
          if (this.refundInfoData[index][spanName] === this.refundInfoData[index - 1][spanName]) {
            spanArr[position] += 1
            spanArr.push(0)
          } else {
            spanArr.push(1)
            position = index
          }
        }
      })
    },
    onGetDetail () {
      let orderId = this.$route.query.orderId
      GetOrderInfoList(orderId).then((res) => {
        // const { profitsharing_status, order_status } = res.data.data || {}
        // let profit = profitsharing_status === '2' // 已結算
        // let noprofit = profitsharing_status === '1' // 未結算

        // let isOne = order_status === 'pay' && profit // 訂單支付成功+已結算
        // let isTwo = order_status === 'refundsuccess' && profit // 訂單退款成功+已結算
        // let isThree = order_status === 'refundfail' && profit // 訂單退款失敗+已結算
        // let isFour = order_status === 'refunding' && noprofit // 訂單退款中+未結算
        // let isFive = order_status === 'refundsuccess' && noprofit // 訂單退款成功+未結算
        // let isSix = order_status === 'refundfail' && noprofit // 訂單退款失敗+未結算
        // if (isOne || isTwo || isThree) { // 分賬信息show：訂單支付成功+已結算、訂單退款成功+已結算、訂單退款失敗+已結算
        //   this.isShowLedger = true
        // }
        // if (isThree || isTwo || isFour || isFive || isSix) { // 退款訂單show：訂單退款中/訂單退款失敗/訂單退款成功+未結算、訂單退款成功+已結算、訂單退款失敗+已結算
        //   this.isShowRefund = true
        // }
        this.orderInfoList = res.data.data
        this.refundInfoData = res.data.data.refund_list
        this.lendgerInfoData = res.data.data.profit_share_list
        this.loading = false
        this.rowspan(this.concatArr, this.testPosition, 'refund_bn')
      })
    }
  }
}
</script>

